// ── 整理分類 & 建立 Prompt ──
const JOURNAL_ORDER = ['NEJM', 'Lancet', 'JAMA', 'BMJ'];
const TYPE_ORDER    = ['RCT', 'MA', 'SR', 'OA'];
const TYPE_DISPLAY  = {
  RCT: 'RCT',
  MA:  'Meta-analysis',
  SR:  'Systematic Review',
  OA:  'Original Article',
};

const items = $input.all().map(i => i.json);

const stats = { RCT:0, MA:0, SR:0, OA:0 };
for (const a of items) { if (a.articleType in stats) stats[a.articleType]++; }

const grouped = {};
for (const j of JOURNAL_ORDER) {
  grouped[j] = {};
  for (const t of TYPE_ORDER) grouped[j][t] = [];
}
for (const a of items) {
  if (grouped[a.journal] && a.articleType in grouped[a.journal])
    grouped[a.journal][a.articleType].push(a);
}
for (const j of JOURNAL_ORDER)
  for (const t of TYPE_ORDER)
    grouped[j][t].sort((a, b) => new Date(b.pubDate || 0) - new Date(a.pubDate || 0));

function getISOWeek(d) {
  const date = new Date(Date.UTC(d.getFullYear(), d.getMonth(), d.getDate()));
  const dow  = date.getUTCDay() || 7;
  date.setUTCDate(date.getUTCDate() + 4 - dow);
  const y1 = new Date(Date.UTC(date.getUTCFullYear(), 0, 1));
  return Math.ceil((((date - y1) / 86400000) + 1) / 7);
}

const now       = new Date();
const weekNum   = String(getISOWeek(now)).padStart(2, '0');
const year      = now.getFullYear();
const timestamp = now.toLocaleString('zh-TW', {
  timeZone: 'Asia/Taipei',
  year: 'numeric', month: '2-digit', day: '2-digit',
  hour: '2-digit', minute: '2-digit', hour12: false,
});
const docTitle  = '【藥師文獻週報】' + year + ' 第' + weekNum + '週';
const total     = items.length;
const SEP       = '══════════════════════════════════════';

const fmtArticle = a =>
  'PMID: '     + a.pmid + '\n' +
  'Journal: '  + a.journal + '\n' +
  'Type: '     + (TYPE_DISPLAY[a.articleType] || a.articleType) + '\n' +
  'Title: '    + a.title + '\n' +
  'Author: '   + (a.firstAuthor || 'N/A') + '\n' +
  'DOI: '      + (a.doi || 'N/A') + '\n' +
  'PubDate: '  + (a.pubDate || 'N/A') + '\n' +
  'Abstract:\n' + (a.abstract || '(no abstract available)');

let articleData = '';
for (const j of JOURNAL_ORDER) {
  const journalArticles = TYPE_ORDER.flatMap(t => grouped[j][t]);
  if (!journalArticles.length) continue;
  articleData += '\n=== ' + j + ' ===\n';
  for (const t of TYPE_ORDER) {
    if (!grouped[j][t].length) continue;
    articleData += '\n-- ' + TYPE_DISPLAY[t] + ' --\n\n';
    for (const a of grouped[j][t]) {
      articleData += fmtArticle(a) + '\n\n---\n\n';
    }
  }
}

const prompt =
'You are a senior clinical pharmacist editor writing for hospital pharmacists in Taiwan. Produce the weekly pharmacist digest.\n' +

'\nCRITICAL RULE: You MUST ONLY summarize the articles explicitly listed in the ARTICLES section below. Do NOT invent, fabricate, generate, or add ANY article that is not in the ARTICLES section. If ARTICLES is empty or contains zero articles, output ONLY the header and the line 【本週無新收錄文章】 then stop.\n' +

'\n════════════════════ LANGUAGE & STYLE RULES ════════════════════\n' +
'- All explanatory text: Traditional Chinese (繁體中文)\n' +
'- Keep in English (NEVER translate or transliterate):\n' +
'    drug names, brand names, trial names, gene names, biomarkers, lab units, journal names\n' +
'- Established Chinese disease terms are acceptable (心房顫動, 糖尿病, 心衰竭, etc.)\n' +
'- NO MARKDOWN anywhere — no **, no *, no # characters\n' +
'- Missing field: write （詳見原文）\n' +

'\n════════════════════ OUTPUT FORMAT ════════════════════\n' +
'\n' + docTitle + '\n' +
'NEJM / Lancet / JAMA / BMJ 精選\n' +
'產製時間：' + timestamp + '\n' +
'\n' + SEP + '\n' +
'本週收錄：' + total + ' 篇\n' +
'RCT：' + stats.RCT + ' 篇｜Meta-analysis：' + stats.MA + ' 篇｜系統性回顧：' + stats.SR + ' 篇｜原著論文：' + stats.OA + ' 篇\n' +
SEP + '\n' +

'\n[For each journal that has articles, in order: NEJM → Lancet → JAMA → BMJ]\n' +
'\n【JOURNAL_NAME】\n' +
'──────────────────────────────────────\n' +
'\n[Within each journal: RCT → Meta-analysis → Systematic Review → Original Article; newest first]\n' +

'\n\n━━ For RCT articles, use this format:\n' +
'▶ [ORIGINAL ENGLISH TITLE — copy verbatim, NEVER translate]\n' +
'  類型：RCT｜作者：[LastName] et al.\n' +
'  DOI：[doi]\n' +
'\n' +
'  背景：[≤2 sentences] 先說明目前治療的缺口或臨床問題，再說明本藥物/介入的作用機制或研究動機。\n' +
'  方法：[≤2 sentences] 研究設計、收案條件（含年齡、疾病嚴重度、基線特徵）、介入 vs 對照、追蹤期間。\n' +
'  結果：[≤2 sentences] 主要終點結果 + 統計數值（HR/RR/OR, 95%CI, P值）；如有重要安全性訊號一併列出。\n' +
'  結論：[exactly 1 sentence] 明確說明藥師在臨床上應注意或可採取的行動（監測指標、用藥調整時機、病人衛教重點等）。\n' +

'\n━━ For Meta-analysis / Systematic Review articles, use this format:\n' +
'▶ [ORIGINAL ENGLISH TITLE — copy verbatim]\n' +
'  類型：[Meta-analysis / Systematic Review]｜作者：[LastName] et al.\n' +
'  DOI：[doi]\n' +
'\n' +
'  背景：[≤2 sentences] 說明此主題的臨床爭議或知識缺口。\n' +
'  方法：[≤2 sentences] 納入研究數、總參與者人數、比較的介入與對照、主要評估指標。\n' +
'  結果：[≤2 sentences] 主要效果量（RR/OR/HR, 95%CI）；必要時說明異質性或證據品質（GRADE）。\n' +
'  結論：[exactly 1 sentence] 明確說明藥師在臨床上應注意或可採取的行動。\n' +

'\n━━ For Original Article articles, use this format:\n' +
'▶ [ORIGINAL ENGLISH TITLE — copy verbatim]\n' +
'  類型：Original Article｜作者：[LastName] et al.\n' +
'  DOI：[doi]\n' +
'\n' +
'  背景：[≤2 sentences] 說明研究問題的臨床重要性。\n' +
'  方法：[≤2 sentences] 研究設計、收案條件（含病人特徵）、主要評估指標。\n' +
'  結果：[≤2 sentences] 主要發現 + 數據。\n' +
'  結論：[exactly 1 sentence] 明確說明藥師在臨床上應注意或可採取的行動。\n' +

'\n[blank line between articles]\n' +
'End the entire document with: 【本週精選完畢】\n' +

'\n════════════════════ ARTICLES ════════════════════\n' +
articleData;

return [{ json: { prompt, docTitle, total, stats } }];

// ── 準備文件內容 ──
// Receives Gemini output ($json.text) and fetches docTitle from upstream.
const digestText = $json.text || '';
const meta = $('整理分類 & 建立 Prompt').first().json;
return [{ json: { digestText, docTitle: meta.docTitle } }];

const EMAIL   = "epyonlee2001@gmail.com";
const API_KEY = "7fc2f56107513e534332a82d43ade08cbb08";
const ENC = s => encodeURIComponent(String(s));

const JOURNALS = [
  { name:"NEJM",   issn:"0028-4793" },
  { name:"Lancet", issn:"0140-6736" },
  { name:"JAMA",   issn:"0098-7484" },
  { name:"BMJ",    issn:"0959-8138" },
];
const TYPES = [
  { code:"RCT", retmax:10, filter:"randomized controlled trial[pt]" },
  { code:"MA",  retmax:10, filter:"meta-analysis[pt]" },
  { code:"SR",  retmax:10, filter:"systematic review[pt]" },
  { code:"OA",  retmax:20,
    filter:"journal article[pt] NOT (randomized controlled trial[pt] OR systematic review[pt] OR meta-analysis[pt] OR review[pt] OR letter[pt] OR editorial[pt] OR comment[pt])" },
];

const now    = new Date();
const cutoff = new Date(now.getTime() - 14 * 24 * 60 * 60 * 1000);
const fmt    = d => d.getFullYear() + "/" + String(d.getMonth()+1).padStart(2,"0") + "/" + String(d.getDate()).padStart(2,"0");
const dateRange = fmt(cutoff) + ":" + fmt(now) + "[edat]";

const BASE_URL = "https://eutils.ncbi.nlm.nih.gov/entrez/eutils/esearch.fcgi";
const common   = "db=pubmed&tool=PharmJournalNewsletter&email=" + ENC(EMAIL) + "&api_key=" + ENC(API_KEY) + "&retmode=json";

const items = [];
for (const j of JOURNALS) {
  for (const t of TYPES) {
    const term = j.issn + "[issn] AND " + dateRange + " AND " + t.filter;
    items.push({ json: {
      journal:     j.name,
      articleType: t.code,
      retmax:      t.retmax,
      url: BASE_URL + "?" + common + "&retmax=" + t.retmax + "&term=" + ENC(term),
    }});
  }
}
return items;

const EMAIL   = "epyonlee2001@gmail.com";
const API_KEY = "7fc2f56107513e534332a82d43ade08cbb08";
const ENC     = s => encodeURIComponent(String(s));
const EFETCH  = "https://eutils.ncbi.nlm.nih.gov/entrez/eutils/efetch.fcgi";
const common  = "db=pubmed&tool=PharmJournalNewsletter&email=" + ENC(EMAIL) + "&api_key=" + ENC(API_KEY) + "&rettype=abstract&retmode=xml";

const seen = new Set();
const batches = [];

for (const item of $input.all()) {
  const d = item.json;
  const ids    = d.esearchresult?.idlist || [];
  const newIds = ids.filter(id => !seen.has(id));
  newIds.forEach(id => seen.add(id));
  if (!newIds.length) continue;
  // Encode journal & articleType into URL so HTTP Request node preserves them
  batches.push({ json: {
    journal:     d.journal,
    articleType: d.articleType,
    pmids:       newIds,
    url: EFETCH + "?" + common + "&id=" + newIds.map(ENC).join(",")
       + "&x_journal=" + ENC(d.journal)
       + "&x_type="    + ENC(d.articleType),
  }});
}

if (!batches.length) {
  return [{ json: { journal:"", articleType:"", pmids:[], url:"", noData:true } }];
}
return batches;

const MONTH_MAP = { Jan:1,Feb:2,Mar:3,Apr:4,May:5,Jun:6,Jul:7,Aug:8,Sep:9,Oct:10,Nov:11,Dec:12 };

const ISSN_MAP = {
  "0028-4793": "NEJM", "1533-4406": "NEJM",
  "0140-6736": "Lancet", "1474-547X": "Lancet",
  "0098-7484": "JAMA", "1538-3598": "JAMA",
  "0959-8138": "BMJ", "1756-1833": "BMJ",
};

// Article types that are kept even without an abstract
const KEEP_WITHOUT_ABSTRACT = new Set(["RCT", "MA", "SR"]);

function getJournalFromBlock(b) {
  const issnM = /<ISSN[^>]*>([^<]+)<\/ISSN>/i.exec(b);
  if (issnM) { const mapped = ISSN_MAP[issnM[1].trim()]; if (mapped) return mapped; }
  const isoM = /<ISOAbbreviation>([^<]+)<\/ISOAbbreviation>/i.exec(b);
  if (isoM) {
    const iso = isoM[1].trim();
    if (/N Engl J Med/i.test(iso)) return "NEJM";
    if (/Lancet/i.test(iso)) return "Lancet";
    if (/JAMA/i.test(iso)) return "JAMA";
    if (/BMJ/i.test(iso)) return "BMJ";
  }
  return "Other";
}

function getArticleTypeFromBlock(b) {
  const ptBlock = (/<PublicationTypeList>([\s\S]*?)<\/PublicationTypeList>/.exec(b)||["",""])[1];
  const types = [...ptBlock.matchAll(/<PublicationType[^>]*>([^<]+)<\/PublicationType>/g)].map(m => m[1]);
  if (types.some(t => /randomized controlled trial/i.test(t))) return "RCT";
  if (types.some(t => /meta-analysis/i.test(t))) return "MA";
  if (types.some(t => /systematic review/i.test(t))) return "SR";
  return "OA";
}

function parseBlock(b) {
  const tag = t => { const x = new RegExp("<" + t + "[^>]*>([\\s\\S]*?)<\\/" + t + ">","i").exec(b); return x?x[1].replace(/<[^>]+>/g,"").trim():""; };
  const pmid = tag("PMID"); if (!pmid) return null;
  const title = tag("ArticleTitle").replace(/\.$/, "").replace(/&amp;/g,"&").replace(/&lt;/g,"<").replace(/&gt;/g,">");
  if (!title) return null;
  const auBlock = (/<AuthorList[^>]*>([\s\S]*?)<\/AuthorList>/.exec(b)||["",""])[1];
  const auM = /<LastName>([^<]+)<\/LastName>/.exec(auBlock);
  const absBlock = (/<Abstract>([\s\S]*?)<\/Abstract>/.exec(b)||["",""])[1];
  let abstract = "";
  if (absBlock) {
    const secs = [...absBlock.matchAll(/<AbstractText(?:[^>]*Label="([^"]*)")?[^>]*>([\s\S]*?)<\/AbstractText>/g)];
    abstract = secs.length ? secs.map(s=>(s[1]?s[1]+": ":"")+s[2].replace(/<[^>]+>/g,"").trim()).join("\n")
                           : absBlock.replace(/<[^>]+>/g,"").trim();
  }
  const doiM = /<ArticleId IdType="doi">([^<]+)<\/ArticleId>/i.exec(b);
  const doi  = doiM ? "https://doi.org/" + doiM[1].trim() : "";
  const pdB  = (/<PubDate>([\s\S]*?)<\/PubDate>/.exec(b)||["",""])[1];
  const yr   = (/<Year>(\d+)<\/Year>/.exec(pdB)||["",""])[1];
  const rawM = (/<Month>([^<]+)<\/Month>/.exec(pdB)||["","01"])[1];
  const dy   = (/<Day>(\d+)<\/Day>/.exec(pdB)||["","01"])[1];
  const mo   = /^\d+$/.test(rawM) ? rawM.padStart(2,"0") : String(MONTH_MAP[rawM]||1).padStart(2,"0");
  const journal     = getJournalFromBlock(b);
  const articleType = getArticleTypeFromBlock(b);

  // Filter: OA without abstract → skip
  if (articleType === "OA" && abstract.length < 50) return null;

  return { pmid, title, firstAuthor:auM?auM[1]:"", abstract, doi,
           pubDate:yr?`${yr}-${mo}-${dy.padStart(2,"0")}`:""  , journal, articleType };
}

const all = [];
for (const item of $input.all()) {
  const d = item.json;
  if (d.noData) continue;
  const xml = d.data || d.body || d.response || "";
  if (!xml || !xml.includes("<PubmedArticle>")) continue;
  const rx = /<PubmedArticle>[\s\S]*?<\/PubmedArticle>/g;
  let m;
  while ((m = rx.exec(xml)) !== null) {
    const art = parseBlock(m[0]);
    if (art) all.push({ json: art });
  }
}
return all.length ? all : [{ json: { pmid:"", journal:"", articleType:"", title:"", firstAuthor:"", abstract:"", doi:"", pubDate:"", noData:true } }];

const raw = $json.text || '';

const TYPE_CFG = {
  'RCT':               { badge: '#1D4ED8', bg: '#EFF6FF' },
  'Meta-analysis':     { badge: '#6D28D9', bg: '#F5F3FF' },
  'Systematic Review': { badge: '#047857', bg: '#ECFDF5' },
  'Original Article':  { badge: '#B45309', bg: '#FFFBEB' },
};
const JOURNAL_CFG = {
  'NEJM':   { color: '#991B1B', accent: '#FEF2F2' },
  'Lancet': { color: '#1E40AF', accent: '#EFF6FF' },
  'JAMA':   { color: '#065F46', accent: '#F0FDF4' },
  'BMJ':    { color: '#1E3A5F', accent: '#EFF6FF' },
};
const TYPE_ORDER = ['RCT', 'Meta-analysis', 'Systematic Review', 'Original Article'];

const esc = s => String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');

// ── Header parsing ──
function parseHeader(text) {
  const h = { title:'', subtitle:'', timestamp:'', stats:'', isCompact:false };
  for (const l of text.split('\n').slice(0,30)) {
    const t = l.trim();
    if (t.includes('藥師文獻週報'))                    h.title     = t;
    else if (t.includes('NEJM')&&t.includes('精選'))   h.subtitle  = t;
    else if (t.includes('產製時間'))                    h.timestamp = t.replace('產製時間：','').trim();
    else if (t.includes('本週收錄'))                    h.stats     = t;
    else if (t.includes('文章數較多')||t.includes('COMPACT')) h.isCompact = true;
  }
  return h;
}

// ── Stats parsing ──
function parseStats(s) {
  const g = re => { const m=s.match(re); return m?m[1]:'0'; };
  return { total:g(/本週收錄：(\d+)/), rct:g(/RCT：(\d+)/), ma:g(/Meta-analysis：(\d+)/), sr:g(/系統性回顧：(\d+)/), oa:g(/原著論文：(\d+)/) };
}

// ── Journal + article parsing ──
// Handles Gemini output which uses ▶ for articles and 類型：X｜作者：Y inline
// Does NOT require -- Type -- section headers
function parseJournals(text) {
  const JOURNAL_NAMES = ['NEJM','Lancet','JAMA','BMJ'];
  const journals = [];
  let curJournal = null;
  let curArt = null;
  let lastField = null;

  const pushArt = () => {
    if (curArt && curJournal) {
      const t = curArt.type || 'Original Article';
      let typeGroup = curJournal.types.find(x => x.name === t);
      if (!typeGroup) { typeGroup = { name: t, articles: [] }; curJournal.types.push(typeGroup); }
      typeGroup.articles.push(curArt);
      curArt = null; lastField = null;
    }
  };

  for (const rawLine of text.split('\n')) {
    const t = rawLine.trim();

    // Journal header: 【NEJM】
    const jm = t.match(/^【(NEJM|Lancet|JAMA|BMJ)】$/);
    if (jm) {
      pushArt();
      curJournal = { name: jm[1], types: [] };
      journals.push(curJournal);
      continue;
    }

    // Article separator / dividers — just flush current article
    if (t === '---' || t === '━━' || /^─+$/.test(t) || /^═+$/.test(t)) {
      pushArt(); continue;
    }

    // Article start: ▶
    if ((t.startsWith('▶') || t.startsWith('\u25B6')) && curJournal) {
      pushArt();
      curArt = { title: t.replace(/^[▶\u25B6]\s*/,'').trim(), type:'', author:'', doi:'', bg:'', method:'', result:'', conclusion:'' };
      lastField = null;
      continue;
    }

    if (curArt) {
      // 類型：RCT｜作者：Smith et al.
      const tam = t.match(/類型：(.+?)｜作者：(.+)/);
      if (tam) { curArt.type = tam[1].trim(); curArt.author = tam[2].trim(); lastField = null; continue; }

      if (t.startsWith('DOI：'))  { curArt.doi        = t.replace('DOI：','').trim();  lastField='doi';        continue; }
      if (t.startsWith('背景：'))  { curArt.bg         = t.replace('背景：','').trim();  lastField='bg';         continue; }
      if (t.startsWith('方法：'))  { curArt.method     = t.replace('方法：','').trim();  lastField='method';     continue; }
      if (t.startsWith('結果：'))  { curArt.result     = t.replace('結果：','').trim();  lastField='result';     continue; }
      if (t.startsWith('結論：'))  { curArt.conclusion = t.replace('結論：','').trim();  lastField='conclusion'; continue; }

      // Continuation line
      if (lastField && lastField !== 'doi' && rawLine.startsWith('  ') && t &&
          !t.startsWith('▶') && !t.startsWith('━') && !t.startsWith('─') && !t.startsWith('【')) {
        curArt[lastField] += ' ' + t;
      }
    }
  }
  pushArt();

  // Sort types within each journal by TYPE_ORDER
  for (const j of journals) {
    j.types.sort((a,b) => {
      const ai = TYPE_ORDER.indexOf(a.name); const bi = TYPE_ORDER.indexOf(b.name);
      return (ai<0?99:ai) - (bi<0?99:bi);
    });
  }
  return journals;
}

// ── Card HTML ──
function cardHTML(art) {
  const cfg = TYPE_CFG[art.type] || TYPE_CFG['Original Article'];
  const doiClean = (art.doi||'').replace(/^https?:\/\/doi\.org\//i,'').replace(/^doi:\s*/i,'');
  const doiHref = doiClean && doiClean !== '（詳見原文）' && doiClean !== 'N/A'
    ? `https://doi.org/${doiClean}` : null;
  const fields = [
    art.bg         && `<p><span class="lbl">背景</span>${esc(art.bg)}</p>`,
    art.method     && `<p><span class="lbl">方法</span>${esc(art.method)}</p>`,
    art.result     && `<p><span class="lbl">結果</span>${esc(art.result)}</p>`,
    art.conclusion && `<p class="concl"><span class="lbl">結論</span>${esc(art.conclusion)}</p>`,
  ].filter(Boolean).join('');
  const body = fields
    ? `<div class="card-body">${fields}</div>`
    : `<p class="compact-note">（原著論文精簡模式，請參閱原文）</p>`;
  return `
<div class="card" style="border-left:4px solid ${cfg.badge};background:${cfg.bg};">
  <span class="badge" style="background:${cfg.badge};">${esc(art.type||'Article')}</span>
  <h3 class="card-title">${esc(art.title)}</h3>
  <div class="card-meta">
    <span>✍ ${esc(art.author||'—')}</span>
    ${doiHref?`<a href="${esc(doiHref)}" target="_blank" class="doi-link">DOI →</a>`:(doiClean&&doiClean!=='N/A'?`<span>${esc(doiClean)}</span>`:'')}
  </div>${body}
</div>`;
}

// ── Journal section HTML ──
function journalHTML(j) {
  const cfg = JOURNAL_CFG[j.name]||{color:'#374151',accent:'#F9FAFB'};
  const sections = j.types.filter(t=>t.articles.length).map(t=>`
<div class="type-sec">
  <div class="type-hdr">${esc(t.name)}</div>
  ${t.articles.map(cardHTML).join('\n')}
</div>`).join('');
  if(!sections.trim()) return '';
  return `
<section class="journal">
  <div class="journal-hdr" style="border-left:6px solid ${cfg.color};background:${cfg.accent};">
    <h2 style="color:${cfg.color};">${esc(j.name)}</h2>
  </div>${sections}
</section>`;
}

// ── Main ──
const hdr    = parseHeader(raw);
const stats  = parseStats(hdr.stats);
