// ── Prepare GitHub Pages Push ──
// Reads HTML binary from upstream 'Text to HTML' node,
// base64-encodes it, and derives the GitHub filename (e.g. 2026-week17.html).
const meta = $('整理分類 & 建立 Prompt').first().json;
const docTitle = meta.docTitle || '';
const total = meta.total || 0;

// Extract year and week from 【藥師文獻週報】2026 第17週
const m = docTitle.match(/(\d{4})\s*第(\d+)週/);
const year = m ? m[1] : String(new Date().getFullYear());
const weekNumInt = m ? parseInt(m[2]) : 1;
const weekNum = String(weekNumInt).padStart(2, '0');
const gitFileName = `${year}-week${weekNum}.html`;

// Base64-encode HTML binary
const buf = await this.helpers.getBinaryDataBuffer($input.first(), 'data');
const htmlBase64 = buf.toString('base64');

// Compute ISO week Monday–Sunday date range for the index card
function isoWeekRange(yr, wk) {
  const jan4 = new Date(Date.UTC(parseInt(yr), 0, 4));
  const dow = jan4.getUTCDay() || 7;
  const mon = new Date(jan4.getTime() - (dow - 1) * 86400000 + (wk - 1) * 7 * 86400000);
  const sun = new Date(mon.getTime() + 6 * 86400000);
  const f = d => `${d.getUTCFullYear()}/${String(d.getUTCMonth()+1).padStart(2,'0')}/${String(d.getUTCDate()).padStart(2,'0')}`;
  return `${f(mon)} – ${f(sun).slice(5)}`;
}

return [{ json: {
  gitFileName,
  htmlBase64,
  year,
  weekNum,
  weekNumInt,
  dateRange: isoWeekRange(year, weekNumInt),
  total,
  commitMessage: `feat: add ${year} week ${weekNum} pharmacist digest`
}}];

// ── Update index.html with new week's card ──
const pushData = $('Prepare GitHub Push').first().json;
const indexResp = $input.first().json;
const currentSha = indexResp.sha;

// Decode current index.html (GitHub returns base64 with newlines)
const currentHtml = Buffer.from(indexResp.content.replace(/\n/g, ''), 'base64').toString('utf-8');

// Build the new card matching the existing index.html structure
const newCard =
`    <a class="issue-card" href="${pushData.gitFileName}">
      <div class="issue-info">
        <h3>第 ${pushData.weekNumInt} 週</h3>
        <span><span class="badge">${pushData.total}篇</span>${pushData.dateRange}</span>
      </div>
      <span class="arrow">→</span>
    </a>`;

// Insert at the top of .card-list
const updatedHtml = currentHtml.replace(
  /(<div class="card-list">)/,
  `$1\n${newCard}`
);

return [{ json: {
  updatedBase64: Buffer.from(updatedHtml, 'utf-8').toString('base64'),
  currentSha,
  commitMessage: `feat: update index for ${pushData.year} week ${pushData.weekNum}`
}}];
